#include <stdio.h>
#include <math.h>

int main(void) {
    int n;
    double sum = 0.0;

    // Read integer n from input
    scanf("%d", &n);

    for (int i = 1; i <= n; i++) {
        // Calculate numerator: 2i+1
        int numerator = 2 * i + 1;

        // Calculate denominator: i²-1
        double denominator = pow(i, 2) - 1.0;

        // Apply alternating signs
        if (i % 2 == 0) {
            sum -= numerator / denominator;
        } else {
            sum += numerator / denominator;
        }
    }

    // Output result with precision
    printf("%.3f\n", sum);

    return 0;
}

#include <stdio.h>

int main(void) {
    int n;

    // Read integer n from the user
    scanf("%d", &n);

    // Generate and print the expanding triangle pattern
    for (int i = 1; i <= n; i++) {
        // Print leading spaces to center the triangle
        for (int j = n - i; j > 0; j--) {
            printf(" ");
        }

        // Print digits repeated i times
        for (int k = 0; k < i; k++) {
            printf("%d", i);
        }

        // Move to the next line after each row
        printf("\n");
    }

    return 0;
}

#include <stdio.h>
#include <stdlib.h>

#define NUM_NUMBERS 5

int main(void) {
    int numbers[NUM_NUMBERS];
    int guessedPositions[NUM_NUMBERS] = {0};
    int score = 0;

    // Generate 5 unique random numbers between 1 and 10
    for (int i = 0; i < NUM_NUMBERS; i++) {
        do {
            numbers[i] = rand() % 10 + 1;
        } while (i > 0 && numbers[i] == numbers[i - 1]);
    }

    // Hide the numbers initially
    printf("Numbers: ");
    for (int i = 0; i < NUM_NUMBERS; i++) {
        printf("*");
    }
    printf("\n");

    // Game loop
    while (score < NUM_NUMBERS) {
        int position;
        char guess[2];

        // Player picks position
        printf("Pick a number between 1 and %d: ", NUM_NUMBERS);
        scanf("%d", &position);

        // Player guesses even or odd
        printf("Guess if the number is 'E'ven or 'O'dd: ");
        scanf("%s", guess);

        // Calculate correctness
        if (numbers[position - 1] % 2 == 0 && guess[0] == 'E') {
            score += 5;
            guessedPositions[position - 1] = 1;
            printf("Correct! You win 5 points.\n");
        } else if (numbers[position - 1] % 2 != 0 && guess[0] == 'O') {
            score += 5;
            guessedPositions[position - 1] = 1;
            printf("Correct! You win 5 points.\n");
        } else {
            printf("Incorrect. Try again.\n");
        }

        // Reveal the number
        printf("Numbers: ");
        for (int i = 0; i < NUM_NUMBERS; i++) {
            if (guessedPositions[i] == 1) {
                printf("%d", numbers[i]);
            } else {
                printf("*");
            }
        }
        printf("\n");
    }

    // Display final score
    printf("Final Score: %d\n", score);

    return 0;
}
